const { execSync } = require('child_process');


const surrealUser = $env.SURREALDB_USER || $env.SURREAL_USER || 'root';
const surrealPass = $env.SURREALDB_PASS || $env.SURREAL_PASS || '';

// Find sources seen 3+ times that don't have a creator entry yet
const sql = `
SELECT url, domain, title, source_type, run_count, reputation_score
FROM source_registry
WHERE run_count >= 3
ORDER BY run_count DESC
LIMIT 50;
`;

let sources = [];
try {
  const result = execSync(`curl -s -X POST http://127.0.0.1:18000/sql -H "Content-Type: application/json" -H "Accept: application/json" -u "${surrealUser}:${surrealPass}" -H "surreal-ns: research" -H "surreal-db: workflow" --data '${sql.replace(/'/g, "\'")}'`, {
    encoding: 'utf-8', timeout: 15000
  });
  const parsed = JSON.parse(result);
  sources = parsed[0]?.result || [];
} catch (err) {
  sources = [];
}

// Get existing creators to avoid duplicates
let existingDomains = new Set();
try {
  const crResult = execSync(`curl -s -X POST http://127.0.0.1:18000/sql -H "Content-Type: application/json" -H "Accept: application/json" -u "${surrealUser}:${surrealPass}" -H "surreal-ns: research" -H "surreal-db: workflow" --data 'SELECT channel_url FROM creator;'`, {
    encoding: 'utf-8', timeout: 10000
  });
  const crParsed = JSON.parse(crResult);
  (crParsed[0]?.result || []).forEach(c => {
    if (c.channel_url) existingDomains.add(c.channel_url);
  });
} catch(e) {}

// Group by domain and identify creator patterns
const domainGroups = {};
for (const src of sources) {
  const domain = src.domain || '';
  if (!domain || domain === 'unknown') continue;
  if (existingDomains.has(src.url)) continue;

  if (!domainGroups[domain]) {
    domainGroups[domain] = { domain, urls: [], total_runs: 0, avg_reputation: 0, source_type: src.source_type };
  }
  domainGroups[domain].urls.push(src.url);
  domainGroups[domain].total_runs += src.run_count || 0;
  domainGroups[domain].avg_reputation = src.reputation_score || 0.5;
}

const candidates = Object.values(domainGroups)
  .filter(g => g.total_runs >= 3)
  .sort((a, b) => b.total_runs - a.total_runs)
  .slice(0, 20);

return [{ json: { candidates, count: candidates.length } }];

const { execSync } = require('child_process');


const candidates = $input.first().json.candidates || [];
if (candidates.length === 0) {
  return [{ json: { creators: [], count: 0 } }];
}

const candidateList = candidates.map(c =>
  `Domain: ${c.domain}, URLs: ${c.urls.slice(0,3).join(', ')}, Type: ${c.source_type}, Runs: ${c.total_runs}`
).join('\n');

const prompt = `Analysiere diese Domains/URLs und klassifiziere sie als Content Creators.

${candidateList}

Fuer jeden identifizierbaren Creator, antworte mit JSON Array:
[{
  "name": "Creator Name oder Domain",
  "platform": "youtube|x|linkedin|substack|reddit|blog|rss|podcast",
  "channel_url": "Haupt-URL",
  "domain_tags": ["tag1", "tag2"],
  "trust_suggestion": "high|medium|watch"
}]

Nur Creators die regelmaessig Inhalte produzieren. Ignoriere generische Domains (github.com, stackoverflow.com, wikipedia.org). NUR JSON Array, kein Markdown.`;

let creators = [];
try {
  const stdout = execSync(`gemini -p "${prompt.replace(/"/g, '\\"')}"`, {
    encoding: 'utf-8',
    timeout: 60000,
    env: { HOME: '/home/clawd', PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin', GEMINI_API_KEY: $env.GEMINI_API_KEY || $env.GOOGLE_GEMINI_API_KEY || '' }
  });

  const jsonMatch = stdout.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    creators = JSON.parse(jsonMatch[0]);
  }
} catch (err) {
  // Fallback: create basic entries from domains
  creators = candidates.slice(0, 10).map(c => ({
    name: c.domain,
    platform: c.source_type === 'youtube' ? 'youtube' : c.source_type === 'social' ? 'x' : 'blog',
    channel_url: c.urls[0] || '',
    domain_tags: [],
    trust_suggestion: c.avg_reputation >= 0.7 ? 'medium' : 'watch'
  }));
}

return [{ json: { creators, count: creators.length } }];

const { execSync } = require('child_process');


const surrealUser = $env.SURREALDB_USER || $env.SURREAL_USER || 'root';
const surrealPass = $env.SURREALDB_PASS || $env.SURREAL_PASS || '';

const creators = $input.first().json.creators || [];
if (creators.length === 0) {
  return [{ json: { inserted: 0, message: 'No new creators found' } }];
}

let sql = '';
let count = 0;

for (const c of creators) {
  if (!c.name || !c.channel_url) continue;

  const validPlatforms = ['youtube', 'x', 'linkedin', 'substack', 'reddit', 'blog', 'rss', 'podcast'];
  const platform = validPlatforms.includes(c.platform) ? c.platform : 'blog';
  const validTrust = ['high', 'medium', 'watch'];
  const trust = validTrust.includes(c.trust_suggestion) ? c.trust_suggestion : 'watch';
  const tags = Array.isArray(c.domain_tags) ? c.domain_tags : [];

  sql += `CREATE creator SET
    name = ${JSON.stringify(c.name)},
    platform = ${JSON.stringify(platform)},
    channel_url = ${JSON.stringify(c.channel_url)},
    trust_level = ${JSON.stringify(trust)},
    domain_tags = ${JSON.stringify(tags)},
    active = true,
    status = 'pending_review',
    discovered_at = time::now();\n`;
  count++;
}

if (sql) {
  try {
    execSync(`curl -s -X POST http://127.0.0.1:18000/sql -H "Content-Type: application/json" -H "Accept: application/json" -u "${surrealUser}:${surrealPass}" -H "surreal-ns: research" -H "surreal-db: workflow" --data '${sql.replace(/'/g, "\'")}'`, {
      encoding: 'utf-8', timeout: 15000
    });
  } catch(e) {}
}

return [{ json: { inserted: count, creators: creators.map(c => c.name) } }];

const { execSync } = require('child_process');


const data = $input.first().json;
const count = data.inserted || 0;

if (count === 0) {
  return [{ json: { notified: false, reason: 'No new creators' } }];
}

const names = (data.creators || []).slice(0, 10).join(', ');
const message = `Creator Discovery: ${count} neue Creator-Kandidaten gefunden\n\n${names}\n\nReview im Portal unter /research/creators`;

const body = JSON.stringify({ chat_id: Number($env.TELEGRAM_CHAT_ID || ''), text: message });

try {
  execSync(`curl -s -X POST -H "Content-Type: application/json" -d '${body.replace(/'/g, "'\\''")}' "https://api.telegram.org/bot${$env.RESEARCH_BOT_TOKEN || ''}/sendMessage"`, {
    encoding: 'utf-8', timeout: 10000
  });
} catch(e) {}

return [{ json: { notified: true, count } }];
